import{_ as t,o as a,c as n,a4 as o}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Adularescence (Moonstone Sheen)","description":"","frontmatter":{"title":"Adularescence (Moonstone Sheen)","phenomenon":"adularescence"},"headers":[],"relativePath":"optical-phenomena/adularescence.md","filePath":"optical-phenomena/adularescence.md","lastUpdated":1784177547000}'),r={name:"optical-phenomena/adularescence.md"};function s(l,e,i,h,c,d){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="adularescence-moonstone-sheen" tabindex="-1">Adularescence (Moonstone Sheen) <a class="header-anchor" href="#adularescence-moonstone-sheen" aria-label="Permalink to &quot;Adularescence (Moonstone Sheen)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The signature effect of moonstone (feldspar family). On a cabochon cut, the gem displays a soft, floating blue-to-white sheen that seems to drift as the stone is rotated — like moonlight on water. Mechanism: alternating thin lamellae of orthoclase and albite (~100–300 nm each). The refractive-index mismatch between layers scatters and interferes with light. This is a structural optical effect, not related to color centers or chromophore elements.</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Lamellar scattering + interference: alternating KAlSi₃O₈ (orthoclase) and NaAlSi₃O₈ (albite) lamellae with thickness on the order of visible light wavelengths. Light scattered across layers interferes coherently; blue light (shorter wavelength) matches the layer spacing for constructive interference, producing the blue/silver sheen. Orange and red (longer wavelengths) interfere destructively, so the effect is always blue-white.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Layers</th><th>Base</th></tr></thead><tbody><tr><td>Blue Moonstone / 蓝月光石</td><td>orthoclase + albite</td><td>feldspar</td></tr><tr><td>Rainbow Moonstone / 彩虹月光石</td><td>fine alternating (rainbow CT interference)</td><td>feldspar</td></tr><tr><td>White Moonstone / 白月光石</td><td>orthoclase + albite (coarser)</td><td>feldspar</td></tr><tr><td>Cat&#39;s-eye Moonstone / 猫眼月光石</td><td>orthoclase + albite + oriented needles</td><td>feldspar</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',8)])])}const f=t(r,[["render",s]]);export{p as __pageData,f as default};
